const data = $('Webhook').first().json.data;
if (!data) return [];

const remoteJid = data.key.remoteJid || '';
if (remoteJid.includes('@g.us')) return [];

const telefone    = remoteJid.split('@')[0];
const nomeContato = data.pushName || telefone;
const msg         = data.message || {};

const texto = (msg.conversation || msg.extendedTextMessage?.text || '').trim();

let tipoMensagem = 'texto';
let arquivoInfo  = null;

if (msg.audioMessage || msg.pttMessage) {
  tipoMensagem = 'audio';
  arquivoInfo  = { mimetype: 'audio/ogg; codecs=opus', extensao: 'ogg', nomeArquivo: `audio_${Date.now()}.ogg` };
} else if (msg.imageMessage) {
  tipoMensagem = 'arquivo';
  arquivoInfo  = { mimetype: msg.imageMessage.mimetype || 'image/jpeg', extensao: 'jpg', nomeArquivo: `img_${Date.now()}.jpg` };
} else if (msg.documentMessage) {
  tipoMensagem = 'arquivo';
  const fname   = msg.documentMessage.fileName || `doc_${Date.now()}.pdf`;
  arquivoInfo   = { mimetype: msg.documentMessage.mimetype || 'application/pdf', extensao: fname.split('.').pop(), nomeArquivo: fname };
} else if (msg.stickerMessage || msg.reactionMessage) {
  return [];
}

if (!texto && tipoMensagem === 'texto') return [];

return [{ json: { telefone, nomeContato, tipoMensagem, texto, arquivoInfo, messageKey: data.key, messageData: data.message } }];

const dadosMsg     = $('Extrair Dados').item.json;
const cfg          = $('Configuração').item.json;
const telefone     = dadosMsg.telefone;
const nomeContato  = dadosMsg.nomeContato;
const tipoMensagem = dadosMsg.tipoMensagem;
const texto        = dadosMsg.texto || '';

const SYSTEM_PROMPT = `Você é a assistente virtual da HealthPrevi, clínica especializada em laudos médicos periciais para processos do INSS, trabalhistas e de seguros.

Colete as seguintes informações em ordem, UMA pergunta por mensagem:

1. Primeiro nome (para cumprimentar)
2. Confirmação: precisa de atestado ou laudo médico?
3. Nome completo
4. CPF
5. Data de nascimento
6. Finalidade: INSS auxílio-doença / auxílio-acidente (pecúlio) / seguro de vida / BPC-LOAS / outro
7. Especialidade médica relacionada ao caso (ortopedista, clínico geral, psiquiatra, neurologista, outra). Informe que pode enviar um áudio se não souber explicar por texto.
8. Se possui documentos antigos (atestados, exames, raio-X) — se sim, peça para enviar agora
9. Se possui prontuário médico — se sim, peça para enviar agora

REGRAS:
- UMA pergunta por mensagem, tom cordial e simples, máximo 3 linhas
- Se receber um áudio transcrito, considere como resposta à pergunta atual e continue
- Ao coletar nome completo, CPF, data de nascimento, finalidade e especialidade, marque concluido: true e envie: 'Perfeito! Em breve nossa equipe da HealthPrevi entrará em contato com você. 😊'
- Responda SEMPRE em português do Brasil

RETORNE APENAS este JSON (sem markdown, sem código, só o JSON):
{
  "mensagem": "texto para o paciente",
  "concluido": false,
  "dados": {
    "nome_curto": null,
    "nome_completo": null,
    "cpf": null,
    "data_nascimento": null,
    "tipo_documento": null,
    "finalidade": null,
    "especialidade": null,
    "tem_atestados": null,
    "tem_exames": null,
    "tem_prontuario": null
  }
}`;

// Pegar conversa existente do Supabase
let conversaRow = null;
try {
  const rows = $input.all();
  const found = rows.find(r => r.json && r.json.telefone === telefone);
  if (found && found.json.telefone) conversaRow = found.json;
} catch(e) {}

// Timeout 10min em aguardando_arquivos
if (conversaRow && conversaRow.estado === 'aguardando_arquivos') {
  if (Date.now() - new Date(conversaRow.updated_at).getTime() > 600000) conversaRow = null;
}

// CONCLUÍDO → silêncio total
if (conversaRow && conversaRow.estado === 'concluido') {
  return [];
}

const estado  = conversaRow ? conversaRow.estado : 'qualificando';
const dados   = conversaRow ? (typeof conversaRow.dados === 'string' ? JSON.parse(conversaRow.dados) : conversaRow.dados) : {};

// historico no formato OpenAI: [{role:'user'|'assistant', content:'...'}]
const historico         = dados.historico         || [];
const arquivosPendentes = dados.arquivos_pendentes || [];
const arquivosColetados = dados.arquivos_coletados || [];
const etapaAtual        = conversaRow ? conversaRow.etapa_arquivo : (arquivosPendentes[0] || null);

function buildGroqPayload(hist) {
  return {
    model: 'llama-3.3-70b-versatile',
    messages: [{ role: 'system', content: SYSTEM_PROMPT }, ...hist],
    temperature: 0.3,
    max_tokens: 500,
    response_format: { type: 'json_object' }
  };
}

// ── ESTADO: qualificando ──────────────────────────────────────
if (estado === 'qualificando') {

  if (tipoMensagem === 'arquivo') {
    historico.push({ role: 'user', content: '[Usuário enviou um documento/imagem durante as perguntas iniciais]' });
    dados.historico = historico;
    return [{ json: { acao: 'groq', telefone, nomeContato, dadosAtuais: dados, groqPayload: buildGroqPayload(historico), groqKey: cfg.groq_key } }];
  }

  if (tipoMensagem === 'audio') {
    return [{ json: {
      acao: 'audio',
      telefone, nomeContato,
      dadosAtuais: dados,
      historico,
      systemPrompt: SYSTEM_PROMPT,
      groqKey: cfg.groq_key,
      messageKey: dadosMsg.messageKey,
      messageData: dadosMsg.messageData
    }}];
  }

  // Texto normal
  historico.push({ role: 'user', content: texto });
  dados.historico = historico;
  return [{ json: { acao: 'groq', telefone, nomeContato, dadosAtuais: dados, groqPayload: buildGroqPayload(historico), groqKey: cfg.groq_key } }];
}

// ── ESTADO: aguardando_arquivos ───────────────────────────────
if (estado === 'aguardando_arquivos') {

  if (tipoMensagem === 'arquivo') {
    return [{ json: { acao: 'arquivo', telefone, nomeContato, etapaAtual, arquivosPendentes, arquivosColetados, dados, arquivoInfo: dadosMsg.arquivoInfo, messageKey: dadosMsg.messageKey, messageData: dadosMsg.messageData } }];
  }

  const idxAtual  = arquivosPendentes.indexOf(etapaAtual);
  const restantes = arquivosPendentes.slice(idxAtual + 1);
  const msgs = { atestados: 'Entendido! Tem exames como raio-X ou ressonância? Pode enviar aqui.', exames: 'Certo! Por último: tem prontuário médico?', prontuario: null };

  if (restantes.length > 0) {
    return [{ json: { acao: 'texto_simples', telefone, nomeContato, mensagemResposta: msgs[etapaAtual] || 'Entendido! Próximo documento?', novoEstado: 'aguardando_arquivos', novaEtapa: restantes[0], novosDados: dados, concluido: false, dadosLead: null } }];
  }

  const dl = { telefone, nome_contato_wa: nomeContato, nome: dados.nome_curto||null, nome_completo: dados.nome_completo||null, cpf: dados.cpf||null, data_nascimento: dados.data_nascimento||null, finalidade: dados.finalidade||null, especialidade: dados.especialidade||null, tem_atestados: (dados.arquivos_coletados||[]).includes('atestados'), tem_exames: (dados.arquivos_coletados||[]).includes('exames'), tem_prontuario: (dados.arquivos_coletados||[]).includes('prontuario') };
  return [{ json: { acao: 'texto_simples', telefone, nomeContato, mensagemResposta: 'Perfeito! Em breve nossa equipe da HealthPrevi entrará em contato com você. 😊', novoEstado: 'concluido', novaEtapa: null, novosDados: dados, concluido: true, dadosLead: dl } }];
}

return [{ json: { acao: 'texto_simples', telefone, nomeContato, mensagemResposta: 'Olá! Em que posso ajudar?', novoEstado: 'qualificando', novaEtapa: null, novosDados: {}, concluido: false, dadosLead: null } }];

const groqText = $json.choices?.[0]?.message?.content || '';
const ctx = $('Processar Decisão').item.json;
const { telefone, nomeContato, dadosAtuais } = ctx;

let parsed;
try {
  const match = groqText.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : groqText);
} catch(e) {
  parsed = { mensagem: 'Desculpe, tive um problema. Pode repetir?', concluido: false, dados: {} };
}

const mensagem   = parsed.mensagem || 'Pode repetir?';
const concluido  = parsed.concluido === true;
const dadosGroq  = parsed.dados || {};

const historico = dadosAtuais.historico || [];
historico.push({ role: 'assistant', content: groqText });

const dadosAtualizados = Object.assign({}, dadosAtuais, { historico });
for (const [k, v] of Object.entries(dadosGroq)) {
  if (v !== null && v !== undefined) dadosAtualizados[k] = v;
}

let novoEstado = 'qualificando';
let novaEtapa  = null;
let dadosLead  = null;

if (concluido) {
  const isSim = v => v === true || v === 'true' || (typeof v === 'string' && v.toLowerCase().startsWith('sim'));
  const pendentes = [];
  if (isSim(dadosAtualizados.tem_atestados)) pendentes.push('atestados');
  if (isSim(dadosAtualizados.tem_exames))    pendentes.push('exames');
  if (isSim(dadosAtualizados.tem_prontuario))pendentes.push('prontuario');
  dadosAtualizados.arquivos_pendentes = pendentes;
  dadosAtualizados.arquivos_coletados = [];
  if (pendentes.length > 0) {
    novoEstado = 'aguardando_arquivos';
    novaEtapa  = pendentes[0];
  } else {
    novoEstado = 'concluido';
    dadosLead  = { telefone, nome_contato_wa: nomeContato, nome: dadosAtualizados.nome_curto||null, nome_completo: dadosAtualizados.nome_completo||null, cpf: dadosAtualizados.cpf||null, data_nascimento: dadosAtualizados.data_nascimento||null, finalidade: dadosAtualizados.finalidade||null, especialidade: dadosAtualizados.especialidade||null, tem_atestados: false, tem_exames: false, tem_prontuario: false };
  }
}

return [{ json: { telefone, nomeContato, mensagemResposta: mensagem, novoEstado, novaEtapa, novosDados: dadosAtualizados, concluido: novoEstado === 'concluido', dadosLead } }];

const base64      = $json.base64;
const mimetype    = $json.mimetype || 'application/octet-stream';
const ctx         = $('Processar Decisão').item.json;
const { telefone, etapaAtual } = ctx;
const arquivoInfo = ctx.arquivoInfo || {};
const fname       = arquivoInfo.nomeArquivo || `arquivo_${Date.now()}`;
const storagePath = `${telefone}/${etapaAtual}/${fname}`;
return [{ json: { telefone, mimetype, storagePath, fname, etapaAtual }, binary: { data: { data: base64, mimeType: mimetype, fileName: fname } } }];

const ctx = $('Processar Decisão').item.json;
const { telefone, nomeContato, arquivosPendentes, arquivosColetados, dados } = ctx;
const etapaAtual = ctx.etapaAtual;
const coletados  = [...(arquivosColetados || []), etapaAtual];
const restantes  = (arquivosPendentes || []).slice((arquivosPendentes||[]).indexOf(etapaAtual) + 1);
dados.arquivos_coletados = coletados;
const msgs = { atestados: 'Atestado recebido! Tem exames como raio-X ou ressonância? Pode enviar.', exames: 'Exames recebidos! Tem prontuário médico?', prontuario: null };
if (restantes.length > 0) {
  return [{ json: { telefone, nomeContato, mensagemResposta: msgs[etapaAtual]||'Documento recebido! Pode enviar o próximo?', novoEstado: 'aguardando_arquivos', novaEtapa: restantes[0], novosDados: dados, concluido: false, dadosLead: null } }];
}
const dl = { telefone, nome_contato_wa: nomeContato, nome: dados.nome_curto||null, nome_completo: dados.nome_completo||null, cpf: dados.cpf||null, data_nascimento: dados.data_nascimento||null, finalidade: dados.finalidade||null, especialidade: dados.especialidade||null, tem_atestados: coletados.includes('atestados'), tem_exames: coletados.includes('exames'), tem_prontuario: coletados.includes('prontuario') };
return [{ json: { telefone, nomeContato, mensagemResposta: 'Perfeito! Todos os documentos recebidos. Em breve nossa equipe entrará em contato. 😊', novoEstado: 'concluido', novaEtapa: null, novosDados: dados, concluido: true, dadosLead: dl } }];

const base64   = $json.base64;
const mimetype = $json.mimetype || 'audio/ogg; codecs=opus';
const ctx      = $('Processar Decisão').item.json;
return [{
  json: {
    telefone:    ctx.telefone,
    nomeContato: ctx.nomeContato,
    dadosAtuais: ctx.dadosAtuais,
    historico:   ctx.historico,
    systemPrompt:ctx.systemPrompt,
    groqKey:     ctx.groqKey
  },
  binary: {
    audio: { data: base64, mimeType: mimetype, fileName: 'audio.ogg' }
  }
}];

const transcricao  = $json.text || '';
const ctx          = $('Preparar Binário Áudio').item.json;
const { telefone, nomeContato, dadosAtuais, systemPrompt, groqKey } = ctx;

const historico = [...(ctx.historico || [])];
historico.push({ role: 'user', content: `[Áudio transcrito]: ${transcricao}` });
dadosAtuais.historico = historico;

const groqPayload = {
  model: 'llama-3.3-70b-versatile',
  messages: [{ role: 'system', content: systemPrompt }, ...historico],
  temperature: 0.3,
  max_tokens: 500,
  response_format: { type: 'json_object' }
};

return [{ json: { telefone, nomeContato, dadosAtuais, groqPayload, groqKey } }];

const groqText = $json.choices?.[0]?.message?.content || '';
const ctx = $('Montar Payload Groq Áudio').item.json;
const { telefone, nomeContato, dadosAtuais } = ctx;

let parsed;
try {
  const m = groqText.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(m ? m[0] : groqText);
} catch(e) {
  parsed = { mensagem: 'Recebi seu áudio! Pode continuar.', concluido: false, dados: {} };
}

const mensagem  = parsed.mensagem || 'Pode continuar?';
const concluido = parsed.concluido === true;
const dadosG    = parsed.dados || {};

const historico = dadosAtuais.historico || [];
historico.push({ role: 'assistant', content: groqText });

const dadosAtualizados = Object.assign({}, dadosAtuais, { historico });
for (const [k, v] of Object.entries(dadosG)) {
  if (v !== null && v !== undefined) dadosAtualizados[k] = v;
}

let novoEstado = 'qualificando', novaEtapa = null, dadosLead = null;
if (concluido) {
  const isSim = v => v === true || v === 'true' || (typeof v === 'string' && v.toLowerCase().startsWith('sim'));
  const pendentes = [];
  if (isSim(dadosAtualizados.tem_atestados)) pendentes.push('atestados');
  if (isSim(dadosAtualizados.tem_exames))    pendentes.push('exames');
  if (isSim(dadosAtualizados.tem_prontuario))pendentes.push('prontuario');
  dadosAtualizados.arquivos_pendentes = pendentes;
  dadosAtualizados.arquivos_coletados = [];
  if (pendentes.length > 0) { novoEstado = 'aguardando_arquivos'; novaEtapa = pendentes[0]; }
  else { novoEstado = 'concluido'; dadosLead = { telefone, nome_contato_wa: nomeContato, nome: dadosAtualizados.nome_curto||null, nome_completo: dadosAtualizados.nome_completo||null, cpf: dadosAtualizados.cpf||null, data_nascimento: dadosAtualizados.data_nascimento||null, finalidade: dadosAtualizados.finalidade||null, especialidade: dadosAtualizados.especialidade||null, tem_atestados: false, tem_exames: false, tem_prontuario: false }; }
}
return [{ json: { telefone, nomeContato, mensagemResposta: mensagem, novoEstado, novaEtapa, novosDados: dadosAtualizados, concluido: novoEstado === 'concluido', dadosLead } }];
